import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://developers.facebook.com/docs/marketing-apis/overview/authentication";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Meta Ads (Facebook Graph) API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:meta-ads",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const metaAdsFirewall = {",
    '  name: "meta-ads",',
    '  description: "Meta Ads (Facebook Graph) API",',
    "  placeholders: {",
    `    META_ADS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://graph.facebook.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.META_ADS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Meta Ads firewall config...");
  const ts = generateTypeScript();
  writeOutput("meta-ads", ts, import.meta.dirname);
}
